import { readdir, stat, lstat } from "node:fs/promises";
import { join, extname, basename, relative } from "node:path";
import { config } from "./config.js";
import { logger } from "./logger.js";
import type { Counters } from "./api-client.js";
import { shouldSkipFolder, shouldSkipPath, resetSkipWarnings } from "@popdam/path-filters";

const SUPPORTED_EXTENSIONS = new Set([".psd", ".ai", ".pdf"]);

// PDF keyword filter: only ingest PDFs whose filename matches these keywords
const PDF_KEYWORDS = [
  "tech pack", "tech_pack", "techpack", "tech-pack",
  "licensing sheet", "licensing-sheet", "licensing_sheet",
  "_comp view", "_compview",
];

export function isPdfCandidate(filename: string): boolean {
  const lower = filename.toLowerCase();
  return PDF_KEYWORDS.some(kw => lower.includes(kw));
}

export interface FileCandidate {
  absolutePath: string;
  relativePath: string; // POSIX canonical (no leading slash)
  filename: string;
  fileType: "psd" | "ai" | "pdf";
  fileSize: number;
  modifiedAt: Date;
  fileCreatedAt: Date | null;
}

/**
 * Validate that all configured scan roots exist and are readable directories.
 * Per WORKER_LOGIC §4.1: refuse to scan if any root is invalid.
 */
export async function validateScanRoots(counters: Counters, scanRoots?: string[], mountRoot?: string): Promise<boolean> {
  const roots = scanRoots ?? config.scanRoots;
  const effectiveMountRoot = mountRoot || config.nasContainerMountRoot;
  let allValid = true;

  for (const root of roots) {
    // Validate against NAS_CONTAINER_MOUNT_ROOT
    if (!root.startsWith(effectiveMountRoot)) {
      logger.error("Scan root is outside NAS_CONTAINER_MOUNT_ROOT", { root, mountRoot: effectiveMountRoot });
      counters.roots_invalid++;
      allValid = false;
      continue;
    }

    try {
      const s = await stat(root);
      if (!s.isDirectory()) {
        logger.error("Scan root is not a directory", { root });
        counters.roots_invalid++;
        allValid = false;
      }
    } catch (e) {
      const code = (e as NodeJS.ErrnoException).code;
      if (code === "ENOENT") {
        logger.error("Scan root does not exist", { root });
        counters.roots_invalid++;
      } else if (code === "EACCES") {
        logger.error("Scan root is not readable", { root });
        counters.roots_unreadable++;
      } else {
        logger.error("Scan root stat failed", { root, error: (e as Error).message });
        counters.roots_invalid++;
      }
      allValid = false;
    }
  }

  return allValid;
}

/**
 * Recursively scan directories and yield file candidates.
 * Per WORKER_LOGIC §4.2: do NOT follow symlinks.
 */
export interface ScanCallbacks {
  shouldAbort?: () => boolean;
  onDir?: (dirPath: string) => void;
  onSkippedDir?: (dirPath: string, reason: string) => void;
}

export async function* scanFiles(
  counters: Counters,
  scanRoots?: string[],
  callbacks?: ScanCallbacks,
  resumeFromDir?: string,
  mountRoot?: string,
): AsyncGenerator<FileCandidate> {
  resetSkipWarnings(); // Reset per-session dedup for skip warnings
  const roots = scanRoots ?? config.scanRoots;
  const effectiveMountRoot = mountRoot || config.nasContainerMountRoot;
  for (const root of roots) {
    if (callbacks?.shouldAbort?.()) return;
    yield* scanDirectory(root, counters, callbacks, root, resumeFromDir, effectiveMountRoot);
  }
}

async function* scanDirectory(
  dirPath: string,
  counters: Counters,
  callbacks?: ScanCallbacks,
  scanRoot?: string,
  resumeFromDir?: string,
  mountRoot?: string,
): AsyncGenerator<FileCandidate> {
  if (callbacks?.shouldAbort?.()) return;
  let entries;
  try {
    entries = await readdir(dirPath, { withFileTypes: true });
    callbacks?.onDir?.(dirPath);
  } catch (e) {
    const code = (e as NodeJS.ErrnoException).code;
    if (code === "EACCES") {
      counters.dirs_skipped_permission++;
      logger.warn("Directory not readable, skipping", { dirPath });
      callbacks?.onSkippedDir?.(dirPath, "EACCES");
    } else {
      logger.warn("Failed to read directory", { dirPath, error: (e as Error).message });
      callbacks?.onSkippedDir?.(dirPath, code || "unknown");
    }
    return;
  }

  // Build a set of lowercased PDF basenames in this directory so we can skip
  // .ai files that have a same-named .pdf sibling (PDF is the canonical form).
  const pdfBasenames = new Set(
    entries
      .filter((e) => extname(e.name).toLowerCase() === ".pdf")
      .map((e) => e.name.toLowerCase().replace(/\.[^.]+$/, "")),
  );

  for (const entry of entries) {
    if (callbacks?.shouldAbort?.()) return;

    const fullPath = join(dirPath, entry.name);

    // §4.2: Do NOT follow symlinks
    try {
      const ls = await lstat(fullPath);
      if (ls.isSymbolicLink()) continue;
    } catch {
      counters.files_stat_failed++;
      continue;
    }

    if (entry.isDirectory()) {
      // Skip excluded directories using centralized path-filters
      if (shouldSkipFolder(entry.name)) {
        logger.debug("Skipping excluded directory", { dirPath: fullPath, folder: entry.name });
        counters.dirs_skipped_excluded++;
        continue;
      }

      // Resume support: if resumeFromDir is set and this is a top-level
      // subdirectory (one level below scan root), skip dirs that sort before it
      if (resumeFromDir && scanRoot && dirPath === scanRoot) {
        if (fullPath < resumeFromDir) {
          logger.debug("Skipping already-checkpointed directory", { dir: fullPath, resumeFrom: resumeFromDir });
          continue;
        }
      }
      yield* scanDirectory(fullPath, counters, callbacks, scanRoot, resumeFromDir, mountRoot);
      continue;
    }

    if (!entry.isFile()) continue;

    counters.files_total_encountered++;

    const ext = extname(entry.name).toLowerCase();
    if (!SUPPORTED_EXTENSIONS.has(ext)) {
      const name = entry.name;
      const JUNK_FILENAMES = new Set([".DS_Store", ".localized", "Thumbs.db", "desktop.ini"]);
      if (
        name.startsWith("._") ||
        name.startsWith("~") ||
        JUNK_FILENAMES.has(name) ||
        dirPath.includes("__MACOSX")
      ) {
        counters.rejected_junk_file++;
      } else {
        counters.rejected_wrong_type++;
      }
      continue;
    }

    // Check full path for excluded segments (catches files nested inside excluded dirs)
    if (shouldSkipPath(fullPath, logger.warn)) {
      counters.rejected_junk_file++;
      continue;
    }

    // PDF keyword filter: only accept PDFs matching specific document types
    if (ext === ".pdf" && !isPdfCandidate(entry.name)) {
      counters.rejected_wrong_type++;
      continue;
    }

    // Skip .ai files when a same-named .pdf sibling exists in the same directory.
    // The PDF is the canonical distributable; the .ai is the editable source.
    if (ext === ".ai") {
      const aiBase = entry.name.toLowerCase().replace(/\.[^.]+$/, "");
      if (pdfBasenames.has(aiBase)) {
        counters.rejected_ai_has_pdf_sibling++;
        logger.debug("Skipping .ai with .pdf sibling", { file: fullPath });
        continue;
      }
    }

    counters.files_checked++;

    try {
      const s = await stat(fullPath);

      // Build canonical relative path (POSIX, no leading slash) per PATH_UTILS.md §1
      const effectiveRoot = mountRoot || config.nasContainerMountRoot;
      let relPath = relative(effectiveRoot, fullPath);
